import{_ as e,a,b as d,c as r,d as o}from"./chunks/复制刷新令牌.IwW3dosg.js";import{_ as n,o as i,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"OneDrive 渠道添加说明","description":"","frontmatter":{},"headers":[],"relativePath":"cn/upload/onedrive.md","filePath":"cn/upload/onedrive.md","lastUpdated":1781962217000}'),c={name:"cn/upload/onedrive.md"};function p(h,t,b,u,m,f){return i(),s("div",null,[...t[0]||(t[0]=[l('<h1 id="onedrive-渠道添加说明" tabindex="-1">OneDrive 渠道添加说明 <a class="header-anchor" href="#onedrive-渠道添加说明" aria-label="Permalink to &quot;OneDrive 渠道添加说明&quot;">​</a></h1><h2 id="添加前要准备什么" tabindex="-1">添加前要准备什么 <a class="header-anchor" href="#添加前要准备什么" aria-label="Permalink to &quot;添加前要准备什么&quot;">​</a></h2><table tabindex="0"><thead><tr><th>需要准备</th><th>用途</th></tr></thead><tbody><tr><td>Microsoft 账号</td><td>用来登录微软后台并授权 OneDrive</td></tr><tr><td>图床域名</td><td>用来填写回调地址</td></tr><tr><td>一个应用注册</td><td>用来生成 <code>Client ID</code> 和 <code>Client Secret</code></td></tr><tr><td>OneDrive 账号</td><td>后面真正存图用</td></tr></tbody></table><h2 id="添加步骤" tabindex="-1">添加步骤 <a class="header-anchor" href="#添加步骤" aria-label="Permalink to &quot;添加步骤&quot;">​</a></h2><h3 id="第一步-进入-microsoft-entra-id" tabindex="-1">第一步：进入 Microsoft Entra ID <a class="header-anchor" href="#第一步-进入-microsoft-entra-id" aria-label="Permalink to &quot;第一步：进入 Microsoft Entra ID&quot;">​</a></h3><ol><li>打开 <code>portal.azure.com</code>。</li><li>顶部搜索 <code>Microsoft Entra ID</code>。</li><li>如果下拉里没有目标入口，就点：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>继续在 Microsoft Entra ID 中搜索</span></span></code></pre></div><ol start="4"><li>进入 <code>Microsoft Entra ID</code>。</li><li>打开 <code>应用注册 / App registrations</code>。</li><li>点击 <code>新注册 / New registration</code>。</li></ol><h3 id="第二步-创建应用" tabindex="-1">第二步：创建应用 <a class="header-anchor" href="#第二步-创建应用" aria-label="Permalink to &quot;第二步：创建应用&quot;">​</a></h3><p>在 <code>New registration</code> 页面里按下面填：</p><table tabindex="0"><thead><tr><th>页面字段</th><th>你该怎么填</th></tr></thead><tbody><tr><td>Name</td><td>你自己起，例如 <code>imgbed-onedrive</code></td></tr><tr><td>Supported account types</td><td>按下面表格选</td></tr><tr><td>Redirect URI 类型</td><td><code>Web</code></td></tr><tr><td>Redirect URI</td><td><code>https://你的域名/api/oauth/onedrive/callback</code></td></tr></tbody></table><p>账号类型怎么选：</p><table tabindex="0"><thead><tr><th>你的场景</th><th>Supported account types 选什么</th></tr></thead><tbody><tr><td>个人 OneDrive</td><td>选个人账号那一项</td></tr><tr><td>个人号和组织号都想支持</td><td>选同时支持个人号和组织号那一项</td></tr><tr><td>只给公司 / 学校 OneDrive 用</td><td>选组织账号那一项</td></tr></tbody></table><p>填完后点击注册</p><p><img src="'+e+'" alt="创建 OneDrive 应用" loading="lazy"></p><h3 id="第三步-记录应用信息" tabindex="-1">第三步：记录应用信息 <a class="header-anchor" href="#第三步-记录应用信息" aria-label="Permalink to &quot;第三步：记录应用信息&quot;">​</a></h3><p>应用创建成功后，在概览页先记下这两个值：</p><table tabindex="0"><thead><tr><th>微软后台字段名</th><th>后面填到哪里</th></tr></thead><tbody><tr><td><code>Application (client) ID</code></td><td>系统里的 <code>Client ID</code></td></tr><tr><td><code>Directory (tenant) ID</code></td><td>组织账号场景下的 <code>Tenant ID</code></td></tr></tbody></table><p><img src="'+a+'" alt="查看应用程序 ID 和目录租户 ID" loading="lazy"></p><h3 id="第四步-创建-client-secret" tabindex="-1">第四步：创建 Client Secret <a class="header-anchor" href="#第四步-创建-client-secret" aria-label="Permalink to &quot;第四步：创建 Client Secret&quot;">​</a></h3><ol><li>进入 <code>Certificates &amp; secrets</code>。</li><li>点击 <code>New client secret</code>。</li><li>名称随便起。</li><li>过期时间按自己习惯选。</li><li>创建后立刻复制 <code>Value</code>。</li></ol><p><img src="'+d+'" alt="保存客户端密码值" loading="lazy"></p><h3 id="第五步-添加权限" tabindex="-1">第五步：添加权限 <a class="header-anchor" href="#第五步-添加权限" aria-label="Permalink to &quot;第五步：添加权限&quot;">​</a></h3><ol><li>进入 <code>API permissions</code>。</li><li>点击 <code>Add a permission</code>。</li><li>选择 <code>Microsoft Graph</code>。</li><li>选择 <code>Delegated permissions</code>。</li><li>添加下面这些权限：</li></ol><table tabindex="0"><thead><tr><th>权限</th><th>作用</th></tr></thead><tbody><tr><td><code>Files.ReadWrite.All</code></td><td>上传、建目录、删文件</td></tr><tr><td><code>offline_access</code></td><td>获取 <code>Refresh Token</code></td></tr><tr><td><code>User.Read</code></td><td>读取账号信息和容量信息</td></tr></tbody></table><h3 id="第六步-回系统里填写-onedrive-渠道" tabindex="-1">第六步：回系统里填写 OneDrive 渠道 <a class="header-anchor" href="#第六步-回系统里填写-onedrive-渠道" aria-label="Permalink to &quot;第六步：回系统里填写 OneDrive 渠道&quot;">​</a></h3><p>在上传设置里选择 <code>OneDrive</code> 后，按下面这套填：</p><table tabindex="0"><thead><tr><th>页面字段</th><th>你该填什么</th></tr></thead><tbody><tr><td>渠道名称</td><td>你自己起，例如 <code>OneDrive主账号</code></td></tr><tr><td>Client ID</td><td>微软后台的 <code>Application (client) ID</code></td></tr><tr><td>Client Secret</td><td>刚才复制的 <code>Client Secret Value</code></td></tr><tr><td>Tenant ID</td><td>按下面表格填</td></tr><tr><td>Refresh Token</td><td>先留空</td></tr><tr><td>根目录</td><td>可选，默认 <code>imgbed</code></td></tr><tr><td>备注</td><td>可选</td></tr></tbody></table><p><img src="'+r+'" alt="回系统填写 OneDrive 渠道配置" loading="lazy"></p><p><code>Tenant ID</code> 填法：</p><table tabindex="0"><thead><tr><th>你刚才选的账号类型</th><th>系统里的 <code>Tenant ID</code> 填什么</th></tr></thead><tbody><tr><td>个人账号</td><td><code>consumers</code></td></tr><tr><td>个人号 + 组织号</td><td><code>common</code></td></tr><tr><td>只给当前组织账号</td><td><code>Directory (tenant) ID</code></td></tr></tbody></table><h3 id="第七步-获取-refresh-token" tabindex="-1">第七步：获取 Refresh Token <a class="header-anchor" href="#第七步-获取-refresh-token" aria-label="Permalink to &quot;第七步：获取 Refresh Token&quot;">​</a></h3><ol><li>在系统里点 <code>获取令牌</code>。</li><li>登录你要绑定的 Microsoft 账号。</li><li>按提示授权。</li><li>授权成功后，回调页会显示一串 <code>Refresh Token</code>。</li><li>复制它。</li><li>回到系统，粘贴到 <code>Refresh Token</code> 输入框里。</li></ol><p><img src="'+o+`" alt="复制刷新令牌" loading="lazy"></p><h3 id="第九步-保存渠道配置" tabindex="-1">第九步：保存渠道配置 <a class="header-anchor" href="#第九步-保存渠道配置" aria-label="Permalink to &quot;第九步：保存渠道配置&quot;">​</a></h3><p>字段填好后直接点击保存。</p><h2 id="渠道流程速查" tabindex="-1">渠道流程速查 <a class="header-anchor" href="#渠道流程速查" aria-label="Permalink to &quot;渠道流程速查&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>打开 portal.azure.com</span></span>
<span class="line"><span>-&gt; 搜索 Microsoft Entra ID</span></span>
<span class="line"><span>-&gt; 进入 应用注册 / App registrations</span></span>
<span class="line"><span>-&gt; 新注册应用</span></span>
<span class="line"><span>-&gt; 填 Name / Supported account types / Web 回调地址</span></span>
<span class="line"><span>-&gt; Register</span></span>
<span class="line"><span>-&gt; 复制 Application (client) ID</span></span>
<span class="line"><span>-&gt; 去 Authentication 检查回调地址</span></span>
<span class="line"><span>-&gt; 去 Certificates &amp; secrets 创建 Client Secret</span></span>
<span class="line"><span>-&gt; 去 API permissions 添加权限</span></span>
<span class="line"><span>-&gt; 回系统填 Client ID / Client Secret / Tenant ID</span></span>
<span class="line"><span>-&gt; 点击 获取令牌</span></span>
<span class="line"><span>-&gt; 复制回调页里的 Refresh Token</span></span>
<span class="line"><span>-&gt; 粘回系统保存</span></span></code></pre></div><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ol><li>Microsoft Entra 应用注册：<a href="https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app</a></li><li>Microsoft 身份平台授权码流程：<a href="https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow</a></li><li>Microsoft Graph 用户身份验证：<a href="https://learn.microsoft.com/en-us/graph/auth-v2-user" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/graph/auth-v2-user</a></li></ol>`,40)])])}const k=n(c,[["render",p]]);export{v as __pageData,k as default};
